            </div>
          );
        })}
      </section>

      <footer className="max-w-2xl mx-auto text-center pt-32 border-t border-gray-100">
          <h3 className="text-3xl serif italic mb-10">Editorial Inquiries</h3>
          <p className="text-base text-gray-500 tracking-wide leading-relaxed mb-12 font-light">
            Each print in the collection is part of a limited edition series. 
            For licensing, collaboration, or high-fidelity prints, please initiate a request.
          </p>
          <Link to="/contact" className="inline-block border border-black px-16 py-5 text-[10px] uppercase tracking-[0.4em] hover:bg-black hover:text-white transition-all duration-500">
            Send Archive Message
          </Link>
      </footer>
    </div>
  );
};

// --- MAIN APP ---
const App: React.FC = () => (
  <HashRouter>
    <Layout>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/contact" element={<Contact />} />
        <Route path="/photographer/:id" element={<PhotographerDetail />} />
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </Layout>
  </HashRouter>
);

const rootElement = document.getElementById('root');
if (rootElement) {
  ReactDOM.createRoot(rootElement).render(<App />);
}

