                   <img 
                    src={image.url} 
                    alt={`Plate ${rowIndex * 5 + imgIndex + 1}`}
                    loading="lazy"
                    className="w-full h-full object-cover transition-transform duration-[2000ms] group-hover/item:scale-110"
                  />

                  {/* Chic Indicator Label */}
