              <h2 className="text-4xl md:text-6xl font-light uppercase tracking-tighter mb-2 leading-tight text-black">
                {photographer.name}
              </h2>
          </div>

          {photographer.collectionTitle && (
            <div className="flex items-center justify-center gap-6 mb-4">
                <div className="h-[1px] w-12 bg-black/10"></div>
                <span className="text-[11px] uppercase tracking-[0.4em] font-medium text-gray-400 italic serif">{photographer.collectionTitle}</span>
                <div className="h-[1px] w-12 bg-black/10"></div>
            </div>
          )}
          <p className="text-[10px] uppercase tracking-[0.5em] text-gray-400 mt-4 animate-bounce">Scroll to view archive</p>
        </section>

        {/* Universal Snap-Gallery Layout */}
        {photographer.images.map((image, index) => (
          <section 
            key={index} 
            className="w-full h-[calc(100vh-64px)] snap-start flex items-center justify-center p-4 md:p-12 bg-[#fcfcfc]"
          >
            <div className="relative h-full w-full flex items-center justify-center group overflow-hidden">
              <img 
                src={image.url} 
                alt={`Photo ${index + 1}`}
                loading="lazy"
                className="max-h-full max-w-full object-contain shadow-2xl transition-all duration-[1200ms] cubic-bezier(0.19, 1, 0.22, 1) group-hover:scale-[1.01]"
              />

              {/* Discrete plate number in the corner */}
              <div className="absolute bottom-6 right-6 opacity-40 group-hover:opacity-100 transition-opacity duration-700">
                <span className="text-[10px] uppercase tracking-[0.4em] font-medium text-black">Entry // 0{index + 1}</span>
              </div>
            </div>
          </section>
        ))}

        {/* Final CTA Section - Final Snap Point */}
        <section className="h-screen snap-start flex flex-col items-center justify-center text-center p-8 bg-white">
          <div className="max-w-xl space-y-12">
            <h3 className="text-4xl md:text-6xl serif italic text-gray-900 leading-tight">
              Inquire regarding the works of {photographer.name.split(' ')[0]}
            </h3>
            <div className="space-y-6">
               <Link to="/contact" className="inline-block border border-black px-16 py-5 text-[10px] uppercase tracking-[0.5em] hover:bg-black hover:text-white transition-all duration-700 font-medium">
                  Open Correspondence
               </Link>
               <div>
                  <Link to="/" className="text-[10px] uppercase tracking-[0.3em] text-gray-400 hover:text-black transition-colors">Return to Home</Link>
               </div>
            </div>
          </div>
        </section>
      </div>
    </div>
  );
};

