// --- Types ---
interface CollectionImage {
  url: string;
  title: string;
  description: string;
  size: 'small' | 'medium' | 'large';
  offset: 'none' | 'top' | 'bottom';
}

interface Portfolio {
  id: string;
  title: string;
  coverImage: string;
  images: CollectionImage[];
}

interface Photographer {
  id: string;
  name: string;
  description: string;
  profileImage: string;
  portfolios: Portfolio[];
  isFeatured?: boolean;
}

interface Event {
  id: string;
  title: string;
  date: string;
  coverImage: string;
  images: CollectionImage[];
  photographerAttribution?: string;
}

