          <Route path="/photographer/:id" element={<PhotographerDetail />} />
          <Route path="/photographer/:id/portfolio/:portfolioId" element={<PortfolioDetail />} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

